import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

// Map weather conditions to emoji icons
const getWeatherEmoji = (condition: string): string => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloudy') || normalized.includes('cloud')) return '☁️';
  if (normalized.includes('rainy') || normalized.includes('rain')) return '🌧️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
  return '🌤️'; // default
};

const getDayLabel = (index: number, dayName?: string): string => {
  return dayName || 'Day ' + (index + 1);
};

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 68, low: 58 },
    { day: 'Wed', icon: '🌧️', high: 62, low: 52 },
    { day: 'Thu', icon: '☁️', high: 70, low: 55 },
    { day: 'Fri', icon: '☀️', high: 78, low: 65 },
  ],
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        maxWidth: '500px',
        margin: '0 auto',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with City */}
        <Text
          variant="h3"
          color="var(--ggui-color-onSurface, #18181b)"
          weight="bold"
        >
          {city}
        </Text>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16} align="center">
          {/* Large Temperature Display */}
          <div
            style={{
              display: 'flex',
              alignItems: 'baseline',
              gap: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            <Text
              variant="h1"
              color="var(--ggui-color-primary-600, #0284c7)"
              weight="bold"
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
              }}
            >
              {temperature}
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
            >
              {unit}
            </Text>
          </div>

          {/* Weather Condition with Emoji */}
          <Stack direction="horizontal" gap={12} align="center" justify="center">
            <div
              style={{
                fontSize: '48px',
                lineHeight: '1',
              }}
            >
              {weatherEmoji}
            </div>
            <Text
              variant="h3"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        />

        {/* Current Conditions Details */}
        <Stack direction="horizontal" gap={16} justify="center" wrap={true}>
          {/* Humidity */}
          <div style={{ textAlign: 'center', flex: '1 1 auto' }}>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="medium"
            >
              Humidity
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
              style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
            >
              {humidity}%
            </Text>
          </div>

          {/* Wind Speed */}
          <div style={{ textAlign: 'center', flex: '1 1 auto' }}>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="medium"
            >
              Wind Speed
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
              style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
            >
              {windSpeed} mph
            </Text>
          </div>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>

          <Row gap={8} wrap={true} justify="between">
            {forecast.map((day, index) => (
              <div
                key={index}
                style={{
                  flex: '1 1 calc(20% - 6px)',
                  minWidth: '70px',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  textAlign: 'center',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  gap: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {/* Day Name */}
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  {getDayLabel(index, day.day)}
                </Text>

                {/* Weather Icon */}
                <div
                  style={{
                    fontSize: '28px',
                    lineHeight: '1',
                  }}
                >
                  {day.icon || '🌤️'}
                </div>

                {/* High/Low Temps */}
                <div style={{ display: 'flex', gap: 'var(--ggui-spacing-1, 4px)', alignItems: 'center' }}>
                  {day.high !== undefined && (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurface, #18181b)"
                      weight="semibold"
                    >
                      {day.high}°
                    </Text>
                  )}
                  {day.low !== undefined && (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      weight="normal"
                    >
                      {day.low}°
                    </Text>
                  )}
                </div>
              </div>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, Button, Badge, Select, Icon } from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks?: Array<Task>;
  columns?: Array<Column>;
  onTaskUpdate?: (payload: { action: string; taskId?: string; data?: Record<string, unknown> }) => void;
}

export default function KanbanBoard({ 
  tasks = [], 
  columns = [],
  onTaskUpdate 
}: Props) {
  const [allTasks, setAllTasks] = useState<Task[]>(tasks);
  const [addingInColumn, setAddingInColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  const defaultColumns = columns.length > 0 ? columns : [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' }
  ];

  const getTasksForColumn = (columnId: string) => 
    allTasks.filter(task => task.column === columnId);

  const getTotalTasks = () => allTasks.length;
  const getCompletedTasks = () => 
    allTasks.filter(task => task.column === 'done').length;

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;

    const taskId = 'task-' + Date.now().toString();
    const newTask: Task = {
      id: taskId,
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '',
      column: columnId,
      dueDate: ''
    };

    setAllTasks(prev => [...prev, newTask]);
    onTaskUpdate?.({ action: 'create', taskId, data: newTask });

    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingInColumn(null);
  };

  const handleMoveTask = (taskId: string, targetColumnId: string) => {
    setAllTasks(prev => 
      prev.map(task => 
        task.id === taskId ? { ...task, column: targetColumnId } : task
      )
    );
    onTaskUpdate?.({ action: 'move', taskId, data: { column: targetColumnId } });
  };

  const handleEditTask = (taskId: string, newTitle: string) => {
    if (!newTitle.trim()) return;
    setAllTasks(prev =>
      prev.map(task =>
        task.id === taskId ? { ...task, title: newTitle } : task
      )
    );
    onTaskUpdate?.({ action: 'edit', taskId, data: { title: newTitle } });
    setEditingTaskId(null);
    setEditingTitle('');
  };

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  const EditTaskView = ({ task }: { task: Task }) => {
    const editTitleLabel = 'Edit Title';
    return (
      <Stack direction="vertical" gap={8}>
        <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Edit Title</Text>
        <Input label={editTitleLabel} value={editingTitle} onChange={setEditingTitle} placeholder="Enter task title" />
        <Row gap={8} justify="end">
          <Button size="xs" variant="primary" onClick={() => handleEditTask(task.id || '', editingTitle)}>
            Save
          </Button>
          <Button size="xs" variant="outline" onClick={() => setEditingTaskId(null)}>
            Cancel
          </Button>
        </Row>
      </Stack>
    );
  };

  const TaskCard = ({ task }: { task: Task }) => (
    <Card
      padding={12}
      shadow="sm"
      border={true}
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        cursor: 'pointer',
        transition: 'all 200ms ease-out',
      }}
    >
      <Stack direction="vertical" gap={8}>
        {editingTaskId === task.id ? (
          <EditTaskView task={task} />
        ) : (
          <Stack direction="horizontal" gap={8} align="start" justify="between">
            <Text
              variant="body"
              weight="medium"
              style={{
                flex: 1,
                wordBreak: 'break-word',
                cursor: 'pointer',
              }}
              onDoubleClick={() => {
                setEditingTaskId(task.id || null);
                setEditingTitle(task.title || '');
              }}
            >
              {task.title}
            </Text>
            <Button
              size="xs"
              variant="ghost"
              onClick={() => {
                setEditingTaskId(task.id || null);
                setEditingTitle(task.title || '');
              }}
            >
              Edit
            </Button>
          </Stack>
        )}

        {task.priority && (
          <Badge variant={getPriorityColor(task.priority)} size="sm">
            {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
          </Badge>
        )}

        <Row gap={8} align="center" justify="between">
          {task.assignee && (
            <div
              style={{
                width: 28,
                height: 28,
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                backgroundColor: 'var(--ggui-color-primary-200, #bae6fd)',
                color: 'var(--ggui-color-primary-900, #0c4a6e)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 'var(--ggui-font-size-xs, 12px)',
                fontWeight: 600,
              }}
            >
              {task.assignee}
            </div>
          )}
          {task.dueDate && (
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {new Date(task.dueDate).toLocaleDateString()}
            </Text>
          )}
        </Row>

        <Select
          label="Move"
          value={task.column || 'todo'}
          onChange={(value) => handleMoveTask(task.id || '', value)}
          options={defaultColumns.map(col => ({
            value: col.id || '',
            label: col.name || ''
          }))}
        />
      </Stack>
    </Card>
  );

  const AddTaskForm = ({ columnId }: { columnId: string }) => {
    const titleLabel = 'Title';
    const priorityLabel = 'Priority';
    return (
      <Card padding={12} shadow="sm" border={true}>
        <Stack direction="vertical" gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">New Task</Text>
          <Input label={titleLabel} placeholder="Enter task title" value={newTaskTitle} onChange={setNewTaskTitle} />
          <Select label={priorityLabel} value={newTaskPriority} onChange={(value) => setNewTaskPriority(value as 'low' | 'medium' | 'high')} options={[
            { value: 'low', label: 'Low' },
            { value: 'medium', label: 'Medium' },
            { value: 'high', label: 'High' }
          ]} />
          <Row gap={8}>
            <Button size="sm" variant="primary" fullWidth onClick={() => handleAddTask(columnId)}>
              Add
            </Button>
            <Button
              size="sm"
              variant="outline"
              fullWidth
              onClick={() => {
                setAddingInColumn(null);
                setNewTaskTitle('');
                setNewTaskPriority('medium');
              }}
            >
              Cancel
            </Button>
          </Row>
        </Stack>
      </Card>
    );
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack direction="vertical" gap={24}>
        {/* Summary Bar */}
        <Card padding={16} shadow="sm">
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap={32}>
              <Stack direction="vertical" gap={4}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Total Tasks
                </Text>
                <Text variant="h2" color="var(--ggui-color-onSurface, #18181b)">
                  {getTotalTasks()}
                </Text>
              </Stack>
              <Stack direction="vertical" gap={4}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Completed
                </Text>
                <Text
                  variant="h2"
                  color="var(--ggui-color-success-600, #16a34a)"
                >
                  {getCompletedTasks()}
                </Text>
              </Stack>
            </Stack>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Progress: {getTotalTasks() > 0 ? Math.round((getCompletedTasks() / getTotalTasks()) * 100) : 0}%
            </Text>
          </Row>
        </Card>

        {/* Kanban Columns */}
        <Row gap={20} align="start" wrap={false}>
          {defaultColumns.map(column => (
            <div
              key={column.id}
              style={{
                flex: '1 1 0',
                minWidth: 320,
                display: 'flex',
                flexDirection: 'column',
                gap: 'var(--ggui-spacing-4, 16px)',
              }}
            >
              {/* Column Header */}
              <Card
                padding={12}
                shadow="none"
                border={true}
                style={{
                  backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                  borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
                }}
              >
                <Row justify="between" align="center">
                  <Stack direction="vertical" gap={4}>
                    <Text
                      variant="label"
                      weight="semibold"
                      color="var(--ggui-color-primary-900, #0c4a6e)"
                    >
                      {column.name}
                    </Text>
                  </Stack>
                  <Badge variant="primary" size="sm">
                    {getTasksForColumn(column.id || '').length}
                  </Badge>
                </Row>
              </Card>

              {/* Tasks List */}
              <Stack direction="vertical" gap={12}>
                {getTasksForColumn(column.id || '').map(task => (
                  <TaskCard key={task.id} task={task} />
                ))}
              </Stack>

              {/* Add Task Section */}
              {addingInColumn === column.id ? (
                <AddTaskForm columnId={column.id || ''} />
              ) : (
                <Button
                  variant="outline"
                  size="sm"
                  fullWidth
                  leftIcon={<Icon name="plus" size={16} />}
                  onClick={() => setAddingInColumn(column.id || '')}
                >
                  Add Task
                </Button>
              )}
            </div>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}
